/**
 * Button 基础样式（极简版，PoC-A 阶段）
 * 等接入 TDesign 主题变量后再切换到 var(--td-*)
 */

.t-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 0 16px;
  border: 1px solid transparent;
  border-radius: 6px;
  font-size: 14px;
  line-height: 1.4;
  cursor: pointer;
  user-select: none;
  background-clip: padding-box;
  transition: background-color 0.2s, border-color 0.2s, color 0.2s;

  // ---- size ----
  &--extra-small { height: 24px; padding: 0 8px;  font-size: 12px; }
  &--small       { height: 32px; padding: 0 12px; font-size: 13px; }
  &--medium      { height: 40px; padding: 0 16px; font-size: 14px; }
  &--large       { height: 48px; padding: 0 20px; font-size: 16px; }

  // ---- shape ----
  &--rectangle { border-radius: 6px; }
  &--square    { border-radius: 6px; padding: 0; aspect-ratio: 1 / 1; }
  &--round     { border-radius: 999px; }
  &--circle    { border-radius: 50%; padding: 0; aspect-ratio: 1 / 1; }

  // ---- variant × theme（仅给出 base + outline 与 default/primary 示意，其余按需扩展） ----
  &--variant-base {
    color: #fff;
    background: #888;
    &.t-button--theme-primary { background: #0052d9; }
    &.t-button--theme-danger  { background: #d54941; }
    &.t-button--theme-warning { background: #ed7b2f; }
    &.t-button--theme-success { background: #2ba471; }
    &.t-button--theme-default { color: #181818; background: #f3f3f3; }
  }

  &--variant-outline {
    background: transparent;
    border-color: currentColor;
    &.t-button--theme-primary { color: #0052d9; }
    &.t-button--theme-danger  { color: #d54941; }
    &.t-button--theme-warning { color: #ed7b2f; }
    &.t-button--theme-success { color: #2ba471; }
    &.t-button--theme-default { color: #181818; border-color: #dcdcdc; }
  }

  &--variant-dashed { border-style: dashed; }
  &--variant-text   { background: transparent; border-color: transparent; }

  // ---- 状态修饰 ----
  &--block    { display: flex; width: 100%; }
  &--disabled { opacity: 0.4; cursor: not-allowed; }
  &--loading  { cursor: progress; }
  &--ghost    { background: transparent !important; color: inherit; }

  // ---- inner ----
  &__icon,
  &__loading,
  &__content { display: inline-flex; align-items: center; }

  &__spinner {
    width: 14px;
    height: 14px;
    border: 2px solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: t-button-spin 0.8s linear infinite;
  }
}

@keyframes t-button-spin {
  to { transform: rotate(360deg); }
}

/**
 * Button 组件的类型契约
 *
 * 这些类型同时被：
 *  - vue3 SFC（button.vue，单测 + H5 端）
 *  - uts SFC（button.uvue，uni-app x App 端）共享
 *
 * 命名遵循 TDesign 现有约定（variant/theme/size/disabled/loading/...）。
 */

export type ButtonVariant = 'base' | 'outline' | 'dashed' | 'text';

export type ButtonTheme = 'default' | 'primary' | 'danger' | 'warning' | 'success';

export type ButtonSize = 'extra-small' | 'small' | 'medium' | 'large';

export type ButtonShape = 'rectangle' | 'square' | 'round' | 'circle';

export type ButtonType = 'button' | 'submit' | 'reset';

export interface ButtonProps {
  variant?: ButtonVariant;
  theme?: ButtonTheme;
  size?: ButtonSize;
  shape?: ButtonShape;
  type?: ButtonType;
  block?: boolean;
  disabled?: boolean;
  loading?: boolean;
  ghost?: boolean;
  /** 透传额外类名 */
  customClass?: string;
}

export interface ButtonEmits {
  (e: 'click', event: MouseEvent): void;
}

/**
 * Button 的变体配置（基于 cva）
 *
 * 类名前缀：t-button
 * 命名约定：
 *  - 互斥变体（variant/theme）使用 `t-button--variant-*` / `t-button--theme-*` 命名空间
 *  - size / shape 是经典枚举，使用扁平命名 `t-button--{value}`
 *  - boolean 修饰使用 `t-button--{flag}`
 */

import { cva } from '../../utils/cva';

export const buttonVariants = cva('t-button', {
  variants: {
    variant: {
      base: 't-button--variant-base',
      outline: 't-button--variant-outline',
      dashed: 't-button--variant-dashed',
      text: 't-button--variant-text',
    },
    theme: {
      default: 't-button--theme-default',
      primary: 't-button--theme-primary',
      danger: 't-button--theme-danger',
      warning: 't-button--theme-warning',
      success: 't-button--theme-success',
    },
    size: {
      'extra-small': 't-button--extra-small',
      small: 't-button--small',
      medium: 't-button--medium',
      large: 't-button--large',
    },
    shape: {
      rectangle: 't-button--rectangle',
      square: 't-button--square',
      round: 't-button--round',
      circle: 't-button--circle',
    },
    block: {
      true: 't-button--block',
    },
    disabled: {
      true: 't-button--disabled',
    },
    loading: {
      true: 't-button--loading',
    },
    ghost: {
      true: 't-button--ghost',
    },
  },
  defaultVariants: {
    variant: 'base',
    theme: 'default',
    size: 'medium',
    shape: 'rectangle',
  },
});
